async function chooseFolder(){
  try{const handle=await showDirectoryPicker({mode:"readwrite",id:"lineage-assets"});if(!await verifyPermission(handle,true))throw Error("需要資料夾讀寫權限，才能儲存專案索引。");await dbPut("root",handle);await openRoot(handle)}catch(e){if(e.name!=="AbortError")showNotice(e.message,true)}
}
async function verifyPermission(h,ask){const opts={mode:"readwrite"};if(await h.queryPermission(opts)==="granted")return true;return ask&&(await h.requestPermission(opts)==="granted")}
async function openRoot(handle){
  state.root=handle;$("folderStatus").textContent=`已開啟：${handle.name}`;$("rescan").disabled=false;
  try{const studio=await handle.getDirectoryHandle(".LineageAssetStudio");const idx=await readJSON(studio,"assets_index.json");state.assets=normalizeAssets(idx);try{const p=await readJSON(studio,"project.json");applyProject(p);state.classificationsSinceBackup=Number(p.backupState?.classificationsSinceBackup)||0;state.lastBackupAt=p.backupState?.lastBackupAt?new Date(p.backupState.lastBackupAt):null}catch{}try{const s=await readJSON(studio,"settings.json");state.scanWarnings=Array.isArray(s.scanWarnings)?s.scanWarnings:[];state.lastScanAt=s.lastScan?new Date(s.lastScan):null;if(validCategoryTree(s.categoryTree)){CATEGORY_TREE=s.categoryTree;CATEGORIES=categoryTreeValues();buildCategoryTree();refreshCategoryControls()}$("scanReport").disabled=!state.lastScanAt}catch{}await initializeBackupSystem();showNotice(`已載入現有索引，共 ${state.assets.length.toLocaleString()} 張圖片。`);afterLoad()}catch(e){if(e.name==="NotFoundError")await scanRoot(true);else showNotice(`索引讀取失敗：${e.message}`,true)}
}

async function scanRoot(){
  if(!state.root)return;
  const previous=Object.fromEntries(state.assets.map(a=>[a.uid,{category:a.category,categoryLabel:a.categoryLabel,categoryPath:a.categoryPath,tags:a.tags,nameId:a.nameId,nameStatus:a.nameStatus,nameSource:a.nameSource,nameConfidence:a.nameConfidence}]));
  setBusy(true,"正在尋找 PNG…",0);state.assets=[];state.selected.clear();
  try{
    const found=[],warnings=[];state.scanWarnings=warnings;state.lastScanAt=new Date();
    await walk(state.root,"",found,warnings);
    if(!found.length)throw Error("在 01.IMG、02.TBT、03.PNG 結構中找不到可讀取的 PNG");
    let done=0,skipped=0;
    for(const item of found){
      const parsed=parsePath(item.path);
      if(!parsed){skipped++;warnings.push(`${item.path}：路徑或檔名不符合索引規則`);continue}
      try{
        const file=await item.handle.getFile(),size=await imageSize(file),old=previous[parsed.uid];
        const inferred=parsed.assetPrefix==="ms"?"Character > 怪物":parsed.assetPrefix==="ge"?"Effect > 其他":"Unknown";
        const label=old?.categoryLabel||old?.category||inferred,path=old?.categoryPath||categoryPathFromLabel(label);
        state.assets.push({...parsed,fileName:file.name,relativePath:item.path,width:size.width,height:size.height,category:label,categoryLabel:label,categoryPath:path,tags:old?.tags||[],nameId:old?.nameId||null,nameStatus:old?.nameStatus||"unassigned",nameSource:old?.nameSource||null,nameConfidence:Number(old?.nameConfidence)||0});
      }catch(e){skipped++;warnings.push(`${item.path}：${e.message}`)}
      done++;
      if(done%20===0||done===found.length){setBusy(true,`正在建立索引 ${done.toLocaleString()} / ${found.length.toLocaleString()}（略過 ${skipped.toLocaleString()}）`,found.length?done/found.length:1);await nextFrame()}
    }
    if(!state.assets.length)throw Error("找到 PNG，但路徑或檔名不符合預期格式（例如 77c.png 或 ms1039.png）");
    state.assets.sort((a,b)=>a.sourceType.localeCompare(b.sourceType)||a.spriteName.localeCompare(b.spriteName,undefined,{numeric:true})||a.originalNumber-b.originalNumber||a.lang.localeCompare(b.lang));
    await createStudioFiles();await initializeBackupSystem();afterLoad();
    const suffix=skipped||warnings.length?`，略過 ${skipped.toLocaleString()} 個不符合命名規則或無法讀取的檔案／資料夾。`:"。";
    showNotice(`掃描完成，共建立 ${state.assets.length.toLocaleString()} 張圖片的索引${suffix}`,warnings.length>0);
    $("scanReport").disabled=false;
    if(warnings.length)console.warn("Lineage Asset Studio 掃描警告：",warnings);
  }catch(e){
    const detail=e?.message||String(e);
    showNotice(`掃描失敗：${detail}。請確認選擇的是 LineageAssets 根目錄，且瀏覽器已取得讀寫權限。`,true);
    console.error("Lineage Asset Studio 掃描失敗",e);
  }finally{setBusy(false)}
}
async function walk(dir,prefix,out,warnings){
  try{
    for await(const [name,h] of dir.entries()){
      if(name===".LineageAssetStudio")continue;
      const p=prefix?`${prefix}/${name}`:name;
      if(h.kind==="directory")await walk(h,p,out,warnings);
      else if(name.toLowerCase().endsWith(".png"))out.push({path:p,handle:h});
    }
  }catch(e){if(!prefix)throw e;warnings.push(`${prefix}：${e.message}`)}
}
function parsePath(path){const parts=path.split("/");if(parts.length<3)return null;const types={"01.IMG":"IMG","02.TBT":"TBT","03.PNG":"PNG"};const sourceType=types[parts[0]];if(!sourceType)return null;const file=parts.at(-1),m=file.match(/^(cs|ms|ge)?(\d+)([chej])?\.png$/i);if(!m)return null;const spriteName=parts.at(-2),assetPrefix=(m[1]||"").toLowerCase(),originalNumber=Number(m[2]),suffix=(m[3]||"").toLowerCase(),langs={c:"TW",h:"CN",j:"JP",e:"EN"},lang=langs[suffix]||"KR",prefixUid=assetPrefix?`_${assetPrefix.toUpperCase()}`:"";return{uid:`${sourceType}_${spriteName}${prefixUid}_${originalNumber}_${lang}`,sourceType,spriteName,assetPrefix,originalNumber,lang}}
async function imageSize(file){try{const b=await createImageBitmap(file);const s={width:b.width,height:b.height};b.close();return s}catch{return await new Promise((resolve,reject)=>{const u=URL.createObjectURL(file),im=new Image();im.onload=()=>{resolve({width:im.naturalWidth,height:im.naturalHeight});URL.revokeObjectURL(u)};im.onerror=()=>{URL.revokeObjectURL(u);reject(Error(`無法讀取圖片：${file.name}`))};im.src=u})}}

function settingsPayload(){return{version:2,groupByOriginalNumber:true,pageSize:PAGE_SIZE,lastScan:(state.lastScanAt||new Date()).toISOString(),scanWarnings:state.scanWarnings,categoryTree:CATEGORY_TREE}}
async function createStudioFiles(){const d=await state.root.getDirectoryHandle(".LineageAssetStudio",{create:true});await d.getDirectoryHandle("thumbnails",{create:true});await d.getDirectoryHandle("cache",{create:true});await d.getDirectoryHandle("backups",{create:true});const data=await d.getDirectoryHandle("data",{create:true});await writeJSON(d,"assets_index.json",indexAssets());await writeJSON(d,"project.json",projectPayload());await writeJSON(d,"settings.json",settingsPayload());await writeJSON(data,"names_catalog.json",state.namesCatalog);await writeJSON(data,"reference_catalog.json",state.referenceCatalog)}
async function writeJSON(dir,name,data){const h=await dir.getFileHandle(name,{create:true}),w=await h.createWritable();await w.write(JSON.stringify(data,null,2));await w.close()}
async function readJSON(dir,name){const h=await dir.getFileHandle(name),f=await h.getFile();return JSON.parse(await f.text())}
