async function saveNameData(){if(!state.root)return;const studio=await state.root.getDirectoryHandle(".LineageAssetStudio",{create:true}),data=await studio.getDirectoryHandle("data",{create:true});state.namesCatalog.updatedAt=new Date().toISOString();await writeJSON(data,"names_catalog.json",state.namesCatalog);await writeJSON(data,"reference_catalog.json",state.referenceCatalog)}
function resolvedName(asset){return asset?.nameId?state.namesCatalog.names[asset.nameId]?.label||null:null}
function normalizeName(value){return String(value||"").trim().normalize("NFKC").toLocaleLowerCase("zh-Hant")}
function hashText(value){let h=2166136261;for(const ch of value){h^=ch.codePointAt(0);h=Math.imul(h,16777619)}return(h>>>0).toString(36)}
function nameTypeFromPath(path){const p=path.toLowerCase();if(p.includes("/items/"))return"item";if(p.includes("/monsters/"))return"monster";if(p.includes("/skills/"))return"skill";if(p.includes("/doll/"))return"doll";if(p.includes("/weapons/"))return"weapon";if(p.includes("/armor"))return"armor";return"other"}
function inferNameSubtype(type,label,path=""){const text=`${label||""} ${path||""}`;if(type==="weapon"){if(/鎖鏈劍/.test(text))return"chain_sword";if(/魔杖|法杖|權杖/.test(text))return"wand";if(/雙手劍|巨劍|大劍/.test(text))return"two_hand_sword";if(/武士刀|太刀/.test(text))return"katana";if(/匕首|短劍/.test(text))return"dagger";if(/弓/.test(text))return"bow";if(/槍|矛/.test(text))return"spear";if(/斧/.test(text))return"axe";if(/劍|刀/.test(text))return"one_hand_sword"}if(type==="armor"){if(/頭盔|頭箍|帽/.test(text))return"helmet";if(/斗篷|披風/.test(text))return"cloak";if(/手套|腕甲/.test(text))return"gloves";if(/靴|鞋/.test(text))return"boots";if(/盾/.test(text))return"shield";if(/內衣/.test(text))return"undershirt";if(/戒指|項鍊|耳環|腰帶|護身符/.test(text))return"accessory";if(/盔甲|鎧甲|胸甲|戰甲|長袍/.test(text))return"body"}if(type==="item"){if(/卷軸|卷軸/.test(text))return"scroll";if(/藥水|藥劑|靈藥/.test(text))return"potion";if(/任務|證明|信件|密令/.test(text))return"quest";if(/材料|礦石|碎片|結晶|木材|皮革/.test(text))return"material";if(/寶石|鑽石|紅寶石|藍寶石|綠寶石/.test(text))return"gem";if(/金幣|貨幣|代幣|硬幣/.test(text))return"currency";if(/箱|袋|包/.test(text))return"box";if(/食物|水果|料理|飲料/.test(text))return"consumable"}if(type==="monster"){if(/boss|首領|王$/i.test(text))return"boss";if(/npc/i.test(text))return"npc";return"normal"}if(type==="skill"){if(/debuff|弱化/i.test(text))return"debuff";if(/buff|強化/i.test(text))return"buff";if(/被動/.test(text))return"passive";return"active"}if(type==="doll")return"doll";return"other"}
function findNameRecord(label){const key=normalizeName(label);return Object.values(state.namesCatalog.names).find(n=>normalizeName(n.label)===key||(n.aliases||[]).some(a=>normalizeName(a)===key))}
function ensureNameRecord(label,reference=null){let record=findNameRecord(label);if(record)return record;const type=reference?.type||"other",subtype=reference?.subtype||inferNameSubtype(type,label,reference?.path)||"other",nameId=`${type}_${hashText(`${label}|${reference?.path||"manual"}`)}`;record={nameId,label:String(label).trim(),aliases:[],type,subtype,categoryPath:[],source:reference?"reference":"manual",sourceRefs:reference?[{referenceId:reference.referenceId,path:reference.path,sourceFile:state.referenceCatalog.sourceFile}]:[],confirmed:!reference,createdAt:new Date().toISOString(),updatedAt:new Date().toISOString()};state.namesCatalog.names[nameId]=record;return record}
function refreshNameSuggestions(){for(const r of state.referenceCatalog.entries||[]){if(!NAME_TYPE_TREE[r.type])r.type="other";if(!r.subtype||r.subtype==="other")r.subtype=inferNameSubtype(r.type,r.label,r.path)}for(const n of Object.values(state.namesCatalog.names)){if(!NAME_TYPE_TREE[n.type])n.type="other";if(!n.subtype||n.subtype==="other")n.subtype=inferNameSubtype(n.type,n.label,n.sourceRefs?.[0]?.path);if(!NAME_TYPE_TREE[n.type].children[n.subtype])n.subtype="other"}renderNameReferenceList()}
function nameTypeLabel(type,subtype=null){const group=NAME_TYPE_TREE[type]||NAME_TYPE_TREE.other;if(!subtype)return group.label;return`${group.label} > ${group.children[subtype]||group.children.other||"其他"}`}
function nameClassMatches(item,value){if(!value)return true;const [type,subtype]=value.split(":");return item.type===type&&(!subtype||item.subtype===subtype)}
function buildNameTypeSelects(){const build=(select,all=true,parents=true)=>{const nodes=[];if(all)nodes.push(new Option("全部名稱分類",""));for(const [type,group]of Object.entries(NAME_TYPE_TREE)){if(parents)nodes.push(new Option(`全部${group.label}`,type));const opt=document.createElement("optgroup");opt.label=group.label;for(const [subtype,label]of Object.entries(group.children))opt.append(new Option(label,`${type}:${subtype}`));nodes.push(opt)}select.replaceChildren(...nodes)};build($("nameTypeFilter"),true,true);build($("namePickerType"),true,true);build($("nameClassEditor"),false,false)}
function renderNameReferenceList(){const root=$("nameReferenceList");if(!root)return;const type=$("nameTypeFilter").value,q=normalizeName($("assetNameInput").value),items=allNameCandidates().filter(x=>nameClassMatches(x,type)&&(!q||normalizeName(x.label).includes(q))).sort((a,b)=>a.type.localeCompare(b.type)||a.subtype.localeCompare(b.subtype)||a.label.localeCompare(b.label,"zh-Hant")).slice(0,300);root.replaceChildren(...items.map(item=>{const b=el("button","name-reference-item");b.type="button";b.append(el("span","",item.label),el("small","",`${nameTypeLabel(item.type,item.subtype)} · ${item.source}`));b.onclick=()=>{const assets=selectedAssets();$("assetNameInput").value=item.label;if(assets.length)assignNameToAssets(item.label,assets);else renderNameReferenceList()};return b}),...(items.length?[]:[el("div","name-reference-empty","此分類沒有符合的名稱")]))}
