  const groups=pageGroups();
  if(e.shiftKey&&state.anchorKey){const a=groups.findIndex(x=>x.key===state.anchorKey),b=groups.findIndex(x=>x.key===g.key);if(a>=0&&b>=0){if(!e.ctrlKey)state.selected.clear();for(let i=Math.min(a,b);i<=Math.max(a,b);i++)setGroupSelected(groups[i],true)}}
