function refreshCategoryControls(){const batch=$("batchCategory").value,filter=$("categoryFilter").value;fillSelect($("batchCategory"),CATEGORIES,false);fillSelect($("categoryFilter"),uniq([...CATEGORIES,...state.assets.map(a=>a.categoryLabel||a.category)]));if(CATEGORIES.includes(batch))$("batchCategory").value=batch;if([...$("categoryFilter").options].some(o=>o.value===filter))$("categoryFilter").value=filter;buildCategoryBrowser()}
async function saveSettings(){if(!state.root)return;if(!state.projectDirty)state.dirtySince=new Date();state.projectDirty=true;try{const d=await state.root.getDirectoryHandle(".LineageAssetStudio",{create:true});await writeJSON(d,"settings.json",settingsPayload())}catch(e){showNotice(`分類樹設定儲存失敗：${e.message}`,true)}}
function handleKeyboard(e){if(e.target.matches("input,textarea,select")||document.querySelector("dialog[open]"))return;const ctrl=e.ctrlKey||e.metaKey;if(ctrl&&e.key.toLowerCase()==="a"){e.preventDefault();currentPageAssets().forEach(a=>state.selected.add(a.uid));render()}else if(e.key==="Escape"){state.selected.clear();render()}else if(e.key==="Delete"){e.preventDefault();applyCategoryValue("Unknown")}else if(ctrl&&e.key.toLowerCase()==="z"){e.preventDefault();undoCategory()}else if(ctrl&&e.key.toLowerCase()==="y"){e.preventDefault();redoCategory()}else if(e.key.toLowerCase()==="f"&&state.appMode==="catalog"){e.preventDefault();toggleCatalogUnknown()}else if(e.key==="Enter"&&state.selected.size){e.preventDefault();applyCategoryValue(state.currentCategory)}}
function clearSelectedTags(){const list=selectedAssets();if(!list.length)return;list.forEach(a=>a.tags=[]);changed(`${list.length} 張圖片的 Tag 已清除。`)}
function confirmDialogTags(){const tags=$("dialogTagInput").value.split(/[,，]/).map(s=>s.trim()).filter(Boolean);if(!tags.length)return;const list=selectedAssets();list.forEach(a=>a.tags=[...new Set([...a.tags,...tags])]);$("tagDialog").close();changed(`${list.length} 張圖片已加入 Tag。`)}
function showSelectedInfo(){const list=selectedAssets();$("infoSummary").textContent=`共 ${list.length.toLocaleString()} 張圖片`;$("infoContent").textContent=list.slice(0,500).map(a=>`${a.uid}\n  ${a.relativePath}\n  ${a.width}×${a.height}｜${a.category}｜${a.tags.join(", ")||"無 Tag"}`).join("\n\n")+(list.length>500?`\n\n…另有 ${list.length-500} 張未顯示`:"");$("infoDialog").showModal()}

function openGroup(g){clearURLs();$("dialogTitle").textContent=`${g.sourceType} / ${g.spriteName} / ${g.assetPrefix||""}${g.originalNumber}`;$("dialogMeta").textContent=`${g.assets.length} 個語言版本`;$("versionGrid").replaceChildren(...g.assets.map(a=>{const v=el("article","version"),t=el("div","thumb");loadAssetImage(a,t);const f=document.createElement("footer"),lab=document.createElement("label"),c=document.createElement("input");c.type="checkbox";c.checked=state.selected.has(a.uid);c.onchange=()=>{c.checked?state.selected.add(a.uid):state.selected.delete(a.uid);updateSelection()};lab.append(c,document.createTextNode(`${a.lang} · ${a.fileName}`));f.append(lab,el("p","",`${a.width} × ${a.height} · ${a.category}`),el("p","",a.tags.length?`# ${a.tags.join("  # ")}`:"尚無 tags"));v.append(t,f);return v}));$("groupDialog").showModal()}
function closeDialog(){$("groupDialog").close();render()}
function updateSelection(){const count=state.selected.size;$("selectionCount").textContent=`已選 ${count.toLocaleString()} 張圖片`;$("hudCount").textContent=`${count.toLocaleString()} 張`;$("hudCategory").textContent=state.currentCategory;$("selectionHud").classList.toggle("hidden",!count);updateCatalogStatus();updateCatalogInspector();renderNameReferenceList()}
function updateCatalogStatus(){if(state.appMode!=="catalog")return;const unknown=state.assets.filter(isUnknown).length;$("statusTotal").textContent=state.assets.length.toLocaleString();$("statusClassified").textContent=(state.assets.length-unknown).toLocaleString();$("statusUnknown").textContent=unknown.toLocaleString();$("statusSelected").textContent=state.selected.size.toLocaleString();$("statusSession").textContent=state.sessionClassified.toLocaleString()}
function updateCatalogInspector(){if(state.appMode!=="catalog")return;const list=selectedAssets();if(!list.length){$("catalogSelectionInfo").textContent="尚未選取素材";$("assetNameInput").value="";$("assetNameMeta").textContent="";$("nameClassEditor").disabled=true;return}const first=list[0],names=[...new Set(list.map(resolvedName).filter(Boolean))],record=first.nameId?state.namesCatalog.names[first.nameId]:null;$("catalogSelectionInfo").textContent=[`已選取：${list.length} 張`,`UID：${first.uid}`,`檔名：${first.fileName}`,`來源：${first.sourceType} / ${first.spriteName}`,`流水號：${first.originalNumber}`,`語言：${first.lang}`,`尺寸：${first.width} × ${first.height}`,`分類：${first.categoryLabel||first.category}`,`名稱：${names.length===1?names[0]:names.length?"多種名稱":"未命名"}`,`Tags：${first.tags.join(", ")||"無"}`,list.length>1?`\n另有 ${list.length-1} 張已選素材`:""].join("\n");$("assetNameInput").value=names.length===1?names[0]:"";$("nameClassEditor").disabled=!record;if(record)$("nameClassEditor").value=`${record.type||"other"}:${record.subtype||"other"}`;$("assetNameMeta").textContent=record?`nameId: ${record.nameId}｜分類：${nameTypeLabel(record.type||"other",record.subtype||"other")}｜來源：${record.source}｜別名：${(record.aliases||[]).join("、")||"無"}`:"輸入名稱後可套用到所有已選素材。"}
function selectedAssets(){return state.assets.filter(a=>state.selected.has(a.uid))}
function applyCategory(){applyCategoryValue($("batchCategory").value)}
function applyCategoryValue(value,record=true){const list=selectedAssets();if(!list.length)return showNotice("請先選取圖片。",true);const oldIndex=Math.max(0,state.visibleAssets.findIndex(a=>state.selected.has(a.uid))),changes=list.filter(a=>(a.categoryLabel||a.category)!==value).map(a=>({uid:a.uid,before:a.categoryLabel||a.category,after:value}));if(!changes.length)return;if(record){state.undo.push(changes);state.redo=[];state.classificationsSinceBackup++}const map=new Map(changes.map(x=>[x.uid,x.after]));state.assets.forEach(a=>{if(map.has(a.uid)){const label=map.get(a.uid);a.category=label;a.categoryLabel=label;a.categoryPath=categoryPathFromLabel(label)}});if(!isUnknown({categoryLabel:value}))state.sessionClassified+=changes.filter(x=>String(x.before).toLowerCase()==="unknown").length;state.currentCategory=value;changed(`${changes.length} 張圖片已套用分類「${value}」。`);if(state.classificationsSinceBackup>=100)createSnapshot("100 次批次分類");if(state.appMode==="catalog"&&!isUnknown({categoryLabel:value})){state.selected.clear();const next=Math.min(oldIndex,Math.max(0,state.visibleAssets.length-1));state.page=Math.floor(next/PAGE_SIZE)+1;render();focusVisibleAsset(state.visibleAssets[next]?.uid)}}
function applyHistory(changes,direction){const map=new Map(changes.map(x=>[x.uid,x[direction]]));state.assets.forEach(a=>{if(map.has(a.uid)){const label=map.get(a.uid);a.category=label;a.categoryLabel=label;a.categoryPath=categoryPathFromLabel(label)}});const delta=changes.reduce((n,x)=>n+(direction==="before"?(String(x.after).toLowerCase()!=="unknown"&&String(x.before).toLowerCase()==="unknown"?-1:0):(String(x.before).toLowerCase()==="unknown"&&String(x.after).toLowerCase()!=="unknown"?1:0)),0);state.sessionClassified=Math.max(0,state.sessionClassified+delta);state.currentCategory=changes.at(-1)?.[direction]||"Unknown";changed(direction==="before"?"已復原上一個分類操作。":"已重做分類操作。")}
function undoCategory(){const changes=state.undo.pop();if(!changes)return;state.redo.push(changes);applyHistory(changes,"before")}
function redoCategory(){const changes=state.redo.pop();if(!changes)return;state.undo.push(changes);applyHistory(changes,"after")}
function addTags(){const tags=$("tagInput").value.split(/[,，]/).map(s=>s.trim()).filter(Boolean),list=selectedAssets();if(!list.length)return showNotice("請先選取圖片。",true);if(!tags.length)return showNotice("請輸入至少一個 tag。",true);list.forEach(a=>a.tags=[...new Set([...a.tags,...tags])]);$("tagInput").value="";changed(`${list.length} 張圖片已加入 tag。`)}
function changed(msg){if(!state.projectDirty)state.dirtySince=new Date();state.projectDirty=true;const page=state.page;buildGroups();buildCategoryBrowser();applyFilters();state.page=Math.min(page,pageCount());render();showNotice(msg);clearTimeout(state.saveTimer);state.saveTimer=setTimeout(saveProject,0)}
async function saveProject(){if(!state.root)return;state.savePromise=state.savePromise.then(async()=>{const d=await state.root.getDirectoryHandle(".LineageAssetStudio",{create:true});await writeJSON(d,"project.json",projectPayload())}).catch(e=>showNotice(`自動儲存失敗：${e.message}`,true));return state.savePromise}

async function importProject(e){const file=e.target.files[0];if(!file)return;try{applyProject(JSON.parse(await file.text()));await saveNameData();changed("專案分類與名稱進度已匯入並儲存。") }catch(err){showNotice(`匯入失敗：${err.message}`,true)}finally{e.target.value=""}}
function exportCSV(){const cols=["uid","sourceType","spriteName","assetPrefix","originalNumber","lang","fileName","relativePath","width","height","category","categoryLabel","categoryPath","nameId","assetName","nameStatus","nameSource","nameConfidence","tags"],q=v=>`"${String(v??"").replaceAll('"','""')}"`,rows=[cols.join(","),...publicAssets().map(a=>({...a,assetName:resolvedName(a)})).map(a=>cols.map(k=>q(k==="tags"?a.tags.join("|"):k==="categoryPath"?a.categoryPath.join("|"):a[k])).join(","))];download("assets_index.csv","\ufeff"+rows.join("\r\n"),"text/csv;charset=utf-8")}
function downloadJSON(name,data){download(name,JSON.stringify(data,null,2),"application/json")}
function download(name,text,type){const u=URL.createObjectURL(new Blob([text],{type})),a=document.createElement("a");a.href=u;a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(u),1000)}

async function openMediaExport(){
  if(!state.root)return showNotice("請先選擇 LineageAssets 資料夾。",true);
  $("mediaExportDialog").showModal();$("mediaFileList").textContent="正在掃描支援的媒體檔案…";state.mediaFiles=[];state.mediaSelected.clear();
  try{await walkMedia(state.root,"",state.mediaFiles);state.mediaFiles.sort((a,b)=>a.path.localeCompare(b.path,undefined,{numeric:true}));const selectedPaths=new Set(selectedAssets().map(a=>a.relativePath.toLowerCase()));state.mediaFiles.forEach(f=>{if(selectedPaths.has(f.path.toLowerCase()))state.mediaSelected.add(f.path)});$("mediaSearch").value="";renderMediaFiles()}catch(e){$("mediaExportDialog").close();showNotice(`媒體掃描失敗：${e.message}`,true)}
}
async function openSelectedMediaExport(){
  const assets=selectedAssets();if(!assets.length)return showNotice("請先選取要匯出的素材。",true);
  $("mediaExportDialog").showModal();$("mediaFileList").textContent="正在準備已選素材…";state.mediaFiles=[];state.mediaSelected.clear();
  try{for(const asset of assets){const handle=await resolveFile(asset.relativePath),ext=fileExtension(asset.fileName);if(MEDIA_EXTS.has(ext))state.mediaFiles.push({name:asset.fileName,path:asset.relativePath,handle,ext,asset})}state.mediaFiles.sort((a,b)=>a.path.localeCompare(b.path,undefined,{numeric:true}));state.mediaFiles.forEach(f=>state.mediaSelected.add(f.path));$("mediaSearch").value="";renderMediaFiles();$("mediaExportSummary").textContent=`已帶入 ${state.mediaFiles.length.toLocaleString()} 個選取素材`}catch(e){$("mediaExportDialog").close();showNotice(`準備匯出失敗：${e.message}`,true)}
}
async function walkMedia(dir,prefix,out){for await(const [name,h] of dir.entries()){if(name===".LineageAssetStudio")continue;const path=prefix?`${prefix}/${name}`:name;if(h.kind==="directory")await walkMedia(h,path,out);else{const ext=fileExtension(name);if(MEDIA_EXTS.has(ext))out.push({name,path,handle:h,ext})}}}
function mediaFiltered(){const q=$("mediaSearch").value.trim().toLowerCase();return q?state.mediaFiles.filter(f=>f.path.toLowerCase().includes(q)):state.mediaFiles}
function renderMediaFiles(){const files=mediaFiltered(),shown=files.slice(0,600),root=$("mediaFileList");root.replaceChildren(...shown.map(f=>{const row=el("label","media-row"),check=document.createElement("input"),name=el("span","",f.name),path=el("code","",f.path);check.type="checkbox";check.checked=state.mediaSelected.has(f.path);check.onchange=()=>{check.checked?state.mediaSelected.add(f.path):state.mediaSelected.delete(f.path);updateMediaCount()};row.append(check,name,path);return row}));if(!files.length)root.append(el("div","media-row","找不到支援的媒體檔案"));if(files.length>shown.length)root.append(el("div","media-row",`僅顯示前 ${shown.length} 筆；可使用搜尋縮小範圍。`));$("mediaExportSummary").textContent=`資料庫內共 ${state.mediaFiles.length.toLocaleString()} 個支援檔案`;updateMediaCount()}
function updateMediaCount(){$("mediaSelectedCount").textContent=`已選 ${state.mediaSelected.size.toLocaleString()} 個`}
function selectAllMedia(){mediaFiltered().forEach(f=>state.mediaSelected.add(f.path));renderMediaFiles()}
async function exportSelectedMedia(){
  const chosen=state.mediaFiles.filter(f=>state.mediaSelected.has(f.path));if(!chosen.length)return showNotice("請先選擇要匯出的媒體檔案。",true);
  let target;try{target=await showDirectoryPicker({mode:"readwrite",id:"lineage-media-export"})}catch(e){if(e.name!=="AbortError")showNotice(e.message,true);return}
  $("confirmMediaExport").disabled=true;let ok=0,failed=[];
  for(const item of chosen){try{const file=await item.handle.getFile(),actual=await detectMediaType(file);if(!sameMediaType(item.ext,actual))throw Error(`內容是 ${actual?.toUpperCase()||"未知格式"}，與副檔名不符`);const toJpg=item.ext==="png"&&$("pngExportFormat").value==="jpg",ext=toJpg?"jpg":item.ext,asset=item.asset||state.assets.find(a=>a.relativePath===item.path),name=mediaExportName(item,asset,ext),output=toJpg?await pngToJpeg(file):file,dir=$("exportCategoryFolders").checked&&asset?await exportCategoryDirectory(target,asset):target;await writeUniqueFile(dir,name,output);ok++}catch(e){failed.push(`${item.path}：${e.message}`)}}
  $("confirmMediaExport").disabled=false;$("mediaExportDialog").close();showNotice(`匯出完成：${ok} 個成功${failed.length?`，${failed.length} 個失敗（詳見瀏覽器主控台）`:""}。`,failed.length>0);if(failed.length)console.warn("媒體匯出失敗",failed)
}
function safeFilePart(value){return String(value||"").replace(/[<>:"/\\|?*\x00-\x1f]/g,"_").replace(/[. ]+$/g,"").trim()||"unnamed"}
function mediaExportName(item,asset,ext){const format=$("mediaNameFormat").value,label=resolvedName(asset),original=replaceExtension(item.name,ext);if(format==="original"||!label)return original;const base=format==="name_uid"?`${safeFilePart(label)}__${safeFilePart(asset.uid)}`:safeFilePart(label);return`${base}.${ext}`}
async function exportCategoryDirectory(root,asset){let dir=root;for(const part of asset.categoryPath||[]){if(String(part).toLowerCase()==="unknown")continue;dir=await dir.getDirectoryHandle(safeFilePart(part),{create:true})}return dir}
async function chooseMediaImport(){
  if(!state.root)return showNotice("請先選擇 LineageAssets 資料夾。",true);if(!window.showOpenFilePicker)return showNotice("此瀏覽器不支援媒體檔案選擇，請使用 Chrome 或 Edge。",true);
  let handles;try{handles=await showOpenFilePicker({multiple:true,excludeAcceptAllOption:true,types:[{description:"支援的媒體檔案",accept:{"image/png":[".png"],"image/jpeg":[".jpg",".jpeg"],"audio/ogg":[".ogg"],"audio/wav":[".wav"],"audio/mpeg":[".mp3"],"video/mp4":[".mp4"]}}]})}catch(e){if(e.name!=="AbortError")showNotice(e.message,true);return}
  const valid=[],invalid=[];for(const h of handles){const f=await h.getFile(),ext=fileExtension(f.name),actual=await detectMediaType(f);if(MEDIA_EXTS.has(ext)&&sameMediaType(ext,actual))valid.push({handle:h,file:f});else invalid.push(`${f.name}（內容格式：${actual||"無法辨識"}）`)}if(!valid.length)return showNotice(`沒有可匯入的有效媒體檔案。${invalid.length?" 部分檔案內容與副檔名不符。":""}`,true);if(invalid.length)console.warn("已拒絕格式不符的匯入檔案",invalid);
  state.importFiles=valid;state.folderStack=[{handle:state.root,name:state.root.name}];$("importFileSummary").textContent=`準備匯入 ${valid.length} 個檔案${invalid.length?`；已拒絕 ${invalid.length} 個格式不符檔案`:""}`;await renderFolderBrowser();$("mediaImportDialog").showModal()
}
async function renderFolderBrowser(){const current=state.folderStack.at(-1),folders=[];for await(const [name,h] of current.handle.entries())if(h.kind==="directory"&&name!==".LineageAssetStudio")folders.push({name,handle:h});folders.sort((a,b)=>a.name.localeCompare(b.name,undefined,{numeric:true}));$("folderPath").textContent=state.folderStack.map(x=>x.name).join(" / ");$("folderUp").disabled=state.folderStack.length===1;$("folderList").replaceChildren(...folders.map(f=>{const row=el("div","folder-row"),name=el("span","",`📁 ${f.name}`),open=el("button","","開啟");row.append(name,open);row.ondblclick=()=>enterFolder(f);open.onclick=()=>enterFolder(f);return row}),...(folders.length?[]:[el("div","folder-row","此位置沒有子資料夾")]))}
async function enterFolder(folder){state.folderStack.push(folder);await renderFolderBrowser()}
async function folderUp(){if(state.folderStack.length>1){state.folderStack.pop();await renderFolderBrowser()}}
async function createImportFolder(){const name=$("newFolderName").value.trim();if(!name||/[<>:"/\\|?*]/.test(name)||name==="."||name==="..")return showNotice("資料夾名稱無效。",true);try{const h=await state.folderStack.at(-1).handle.getDirectoryHandle(name,{create:true});$("newFolderName").value="";await renderFolderBrowser();showNotice(`已建立資料夾「${name}」。`)}catch(e){showNotice(`建立資料夾失敗：${e.message}`,true)}}
async function importToCurrentFolder(){const target=state.folderStack.at(-1).handle;$("confirmMediaImport").disabled=true;let ok=0,failed=[];for(const item of state.importFiles){try{await writeUniqueFile(target,item.file.name,item.file);ok++}catch(e){failed.push(`${item.file.name}：${e.message}`)}}$("confirmMediaImport").disabled=false;$("mediaImportDialog").close();showNotice(`匯入完成：${ok} 個成功${failed.length?`，${failed.length} 個失敗`:""}。若匯入 PNG 到素材結構，請按「重新掃描」。`,failed.length>0);if(failed.length)console.warn("媒體匯入失敗",failed)}
function fileExtension(name){return(name.split(".").pop()||"").toLowerCase()}
function replaceExtension(name,ext){return name.replace(/\.[^.]+$/,"")+`.`+ext}
function sameMediaType(ext,type){return(ext==="jpg"||ext==="jpeg")?type==="jpg":ext===type}
async function detectMediaType(file){const b=new Uint8Array(await file.slice(0,16).arrayBuffer()),ascii=(s,e)=>String.fromCharCode(...b.slice(s,e));if(b[0]===0x89&&ascii(1,4)==="PNG")return"png";if(b[0]===0xff&&b[1]===0xd8&&b[2]===0xff)return"jpg";if(ascii(0,4)==="OggS")return"ogg";if(ascii(0,4)==="RIFF"&&ascii(8,12)==="WAVE")return"wav";if(ascii(0,3)==="ID3"||(b[0]===0xff&&(b[1]&0xe0)===0xe0))return"mp3";if(ascii(4,8)==="ftyp")return"mp4";return null}
async function pngToJpeg(file){const image=await createImageBitmap(file),canvas=document.createElement("canvas");canvas.width=image.width;canvas.height=image.height;const ctx=canvas.getContext("2d");ctx.fillStyle="#ffffff";ctx.fillRect(0,0,canvas.width,canvas.height);ctx.drawImage(image,0,0);image.close();return new Promise((resolve,reject)=>canvas.toBlob(b=>b?resolve(b):reject(Error("JPG 轉換失敗")),"image/jpeg",0.92))}
async function writeUniqueFile(dir,requestedName,data){const dot=requestedName.lastIndexOf("."),base=dot>0?requestedName.slice(0,dot):requestedName,ext=dot>0?requestedName.slice(dot):"";let name=requestedName,n=1;while(await fileExists(dir,name))name=`${base} (${n++})${ext}`;const h=await dir.getFileHandle(name,{create:true}),w=await h.createWritable();await w.write(data);await w.close();return name}
async function fileExists(dir,name){try{await dir.getFileHandle(name);return true}catch(e){if(e.name==="NotFoundError")return false;throw e}}

async function initializeBackupSystem(){if(!state.root)return;try{const studio=await state.root.getDirectoryHandle(".LineageAssetStudio",{create:true});await studio.getDirectoryHandle("backups",{create:true});await loadNameData(studio);$("createBackup").disabled=false;$("viewBackups").disabled=false;await refreshBackupStats()}catch(e){showNotice(`專案資料初始化失敗：${e.message}`,true)}}
function backupTimestamp(date=new Date()){const p=n=>String(n).padStart(2,"0");return`${date.getFullYear()}-${p(date.getMonth()+1)}-${p(date.getDate())}_${p(date.getHours())}-${p(date.getMinutes())}-${p(date.getSeconds())}`}
async function backupDirectory(){const studio=await state.root.getDirectoryHandle(".LineageAssetStudio",{create:true});return studio.getDirectoryHandle("backups",{create:true})}
async function listBackupFiles(){const dir=await backupDirectory(),items=[];for await(const [name,h]of dir.entries()){if(h.kind==="file"&&name.toLowerCase().endsWith(".json")){const file=await h.getFile();items.push({name,handle:h,size:file.size,lastModified:file.lastModified,file})}}return items.sort((a,b)=>b.lastModified-a.lastModified)}
async function refreshBackupStats(){const all=await listBackupFiles(),snapshots=all.filter(x=>/^project_\d{4}-\d{2}-\d{2}_\d{2}-\d{2}-\d{2}\.json$/.test(x.name));state.backupCount=snapshots.length;if(snapshots.length){const latest=new Date(snapshots[0].lastModified);if(!state.lastBackupAt||latest>state.lastBackupAt)state.lastBackupAt=latest}updateBackupStatus();return all}
function updateBackupStatus(){const label=state.lastBackupAt?state.lastBackupAt.toLocaleString():"尚無";$("backupStatus").textContent=state.lastBackupAt?`最近備份 ${label}｜共 ${state.backupCount} 份`:`尚無備份｜共 ${state.backupCount} 份`;if($("statusBackup"))$("statusBackup").textContent=label}
async function uniqueBackupName(dir,prefix="project"){const now=Date.now();for(let i=0;i<120;i++){const name=`${prefix}_${backupTimestamp(new Date(now+i*1000))}.json`;if(!await fileExists(dir,name))return name}throw Error("無法建立唯一備份檔名")}
async function createSnapshot(reason="auto"){
  if(!state.root||state.backupBusy)return;state.backupBusy=true;$("createBackup").disabled=true;
  const oldCount=state.classificationsSinceBackup,oldTime=state.lastBackupAt,oldDirty=state.projectDirty,oldSince=state.dirtySince;
  try{await saveProject();const dir=await backupDirectory(),name=await uniqueBackupName(dir,"project");state.classificationsSinceBackup=0;state.lastBackupAt=new Date();state.projectDirty=false;state.dirtySince=null;await writeJSON(dir,name,{...projectPayload(),snapshot:{reason,createdAt:state.lastBackupAt.toISOString()}});await enforceBackupRetention(dir);await saveProject();await refreshBackupStats();showNotice(`已建立備份：${name}`)}catch(e){state.classificationsSinceBackup=oldCount;state.lastBackupAt=oldTime;state.projectDirty=oldDirty;state.dirtySince=oldSince;showNotice(`建立備份失敗：${e.message}`,true)}finally{state.backupBusy=false;$("createBackup").disabled=false}
}
async function enforceBackupRetention(dir){const files=[];for await(const [name,h]of dir.entries())if(h.kind==="file"&&/^project_\d{4}-\d{2}-\d{2}_\d{2}-\d{2}-\d{2}\.json$/.test(name)){const f=await h.getFile();files.push({name,time:f.lastModified})}files.sort((a,b)=>b.time-a.time);for(const old of files.slice(20))await dir.removeEntry(old.name)}
async function checkTimedBackup(){if(!state.root||!state.projectDirty||!state.dirtySince||state.backupBusy)return;if(Date.now()-state.dirtySince.getTime()>=30*60*1000)await createSnapshot("30 分鐘自動備份")}
async function openBackupDialog(){$("backupDialog").showModal();$("backupList").textContent="正在讀取備份…";try{const files=await refreshBackupStats();$("backupDialogSummary").textContent=`共 ${files.length} 個備份檔；自動快照最多保留 20 份`;$("backupList").replaceChildren(...files.map(item=>{const row=el("div","backup-row"),name=el("span","",item.name),time=document.createElement("time"),size=el("small","",formatBytes(item.size)),restore=el("button","","還原此備份");time.textContent=new Date(item.lastModified).toLocaleString();restore.onclick=()=>restoreBackup(item);row.append(name,time,size,restore);return row}),...(files.length?[]:[el("div","backup-row","目前沒有備份")]))}catch(e){$("backupList").textContent=`讀取失敗：${e.message}`}}
function formatBytes(bytes){if(bytes<1024)return`${bytes} B`;if(bytes<1048576)return`${(bytes/1024).toFixed(1)} KB`;return`${(bytes/1048576).toFixed(1)} MB`}
async function restoreBackup(item){if(!confirm(`確定還原 ${item.name}？\n目前 project.json 會先建立 emergency backup。`))return;const restoreButtons=$("backupList").querySelectorAll("button");restoreButtons.forEach(b=>b.disabled=true);try{const data=JSON.parse(await item.file.text());if(!data||typeof data.assets!=="object")throw Error("備份格式不正確");await saveProject();const studio=await state.root.getDirectoryHandle(".LineageAssetStudio",{create:true}),dir=await studio.getDirectoryHandle("backups",{create:true}),emergency=await uniqueBackupName(dir,"emergency_backup");await writeJSON(dir,emergency,projectPayload());await writeJSON(studio,"project.json",data);state.assets=normalizeAssets(await readJSON(studio,"assets_index.json"));applyProject(data);state.classificationsSinceBackup=Number(data.backupState?.classificationsSinceBackup)||0;state.lastBackupAt=data.backupState?.lastBackupAt?new Date(data.backupState.lastBackupAt):state.lastBackupAt;state.projectDirty=false;state.dirtySince=null;state.selected.clear();state.undo=[];state.redo=[];CATEGORIES=categoryTreeValues();buildCategoryTree();refreshCategoryControls();await writeJSON(studio,"settings.json",settingsPayload());afterLoad();await refreshBackupStats();$("backupDialog").close();showNotice(`已還原 ${item.name}；還原前資料已保存為 ${emergency}。`)}catch(e){showNotice(`還原備份失敗：${e.message}`,true);restoreButtons.forEach(b=>b.disabled=false)}}

function reportLines(){return state.scanWarnings.length?state.scanWarnings:["沒有無法讀取的檔案或資料夾。"]}
function openReport(){$("reportSearch").value="";renderReport();$("reportDialog").showModal()}
function renderReport(){const q=$("reportSearch").value.trim().toLowerCase(),all=reportLines(),shown=q?all.filter(x=>x.toLowerCase().includes(q)):all;$("reportSummary").textContent=`掃描時間：${state.lastScanAt?.toLocaleString()||"尚未掃描"}｜警告 ${state.scanWarnings.length.toLocaleString()} 筆${q?`｜符合 ${shown.length.toLocaleString()} 筆`:""}`;$("reportContent").textContent=shown.join("\n")}
async function copyReport(){try{await navigator.clipboard.writeText(reportText());$("copyReport").textContent="已複製";setTimeout(()=>$("copyReport").textContent="複製報告",1500)}catch{showNotice("無法使用剪貼簿，請改用下載報告。",true)}}
function downloadReport(){download("lineage_asset_scan_report.txt","\ufeff"+reportText(),"text/plain;charset=utf-8")}
function reportText(){return["Lineage Asset Studio 掃描報告",`時間：${state.lastScanAt?.toLocaleString()||"尚未掃描"}`,`警告數：${state.scanWarnings.length}`,"",...reportLines()].join("\r\n")}

function fillSelect(select,items,numeric=false){const first=select.options[0]?.value===""?select.options[0].cloneNode(true):null;select.replaceChildren(...(first?[first]:[]),...items.sort(numeric?(a,b)=>a.localeCompare(b,undefined,{numeric:true}):undefined).map(v=>new Option(v,v)))}
function uniq(a,numeric=false){return [...new Set(a)].sort(numeric?(x,y)=>x.localeCompare(y,undefined,{numeric:true}):undefined)}
function el(tag,cls="",text=""){const e=document.createElement(tag);e.className=cls;if(text!=="")e.textContent=text;return e}
function showNotice(text,error=false){const n=$("notice");n.textContent=text;n.className="notice"+(error?" error":"");clearTimeout(showNotice.timer);if(!error)showNotice.timer=setTimeout(()=>n.classList.add("hidden"),6000)}
function setBusy(on,text="",ratio=0){$("progress").classList.toggle("hidden",!on);$("progress").querySelector("div").style.width=`${Math.round(ratio*100)}%`;$("progress").querySelector("span").textContent=text;$("chooseFolder").disabled=on;$("rescan").disabled=on||!state.root}
const nextFrame=()=>new Promise(r=>requestAnimationFrame(r));
function db(){return new Promise((res,rej)=>{const r=indexedDB.open(DB_NAME,1);r.onupgradeneeded=()=>r.result.createObjectStore(STORE);r.onsuccess=()=>res(r.result);r.onerror=()=>rej(r.error)})}
async function dbGet(k){const d=await db();return new Promise((res,rej)=>{const r=d.transaction(STORE).objectStore(STORE).get(k);r.onsuccess=()=>res(r.result);r.onerror=()=>rej(r.error)})}
async function dbPut(k,v){const d=await db();return new Promise((res,rej)=>{const r=d.transaction(STORE,"readwrite").objectStore(STORE).put(v,k);r.onsuccess=()=>res();r.onerror=()=>rej(r.error)})}
